from typing import List

class Solution:
    def checkArray(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        diff = [0] * (n + 1)  # difference array for active decrements
        active = 0            # current total decrement affecting i

        for i in range(n):
            active += diff[i]
            cur = nums[i] - active
            if cur < 0:
                return False  # would require undoing decrements

            if cur > 0:
                # Must start decrements at i, spanning [i, i+k-1]
                if i + k > n:
                    return False
                active += cur
                diff[i + k] -= cur  # remove effect after i+k-1

        return True
